#include <stdio.h>
#include <math.h>

int main(void) {
    int n;
    double sum = 0.0;

    // Read integer n from input
    scanf("%d", &n);

    for (int i = 1; i <= n; i++) {
        // Calculate numerator: 2i+1
        int numerator = 2 * i + 1;

        // Calculate denominator: i²-1
        double denominator = pow(i, 2) - 1;

        // Apply alternating signs using (-1)^(i+1)
        sum += (i % 2 == 0) ? -numerator / denominator : numerator / denominator;
    }

    // Output result with precision
    printf("%.3f\n", sum);

    return 0;
}

