#include <stdio.h>
#include <math.h>

double distance(double x1, double y1, double x2, double y2) {
    return sqrt((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1));
}

int main(void) {
    double x[4], y[4];
    for (int i = 0; i < 4; i++) scanf("%lf %lf", &x[i], &y[i]);

    // Generate all combinations of 3 points
    for (int a = 0; a < 3; a++) {
        for (int b = a + 1; b < 4; b++) {
            for (int c = b + 1; c < 4; c++) {
                // Check if the points are collinear
                double d1 = distance(x[a], y[a], x[b], y[b]);
                double d2 = distance(x[b], y[b], x[c], y[c]);
                double d3 = distance(x[a], y[a], x[c], y[c]);

                if (d1 + d2 <= d3 || d1 + d3 <= d2 || d2 + d3 <= d1) {
                    printf("collinear\n");
                    continue;
                }

                // Calculate the semi-perimeter
                double s = (d1 + d2 + d3) / 2.0;

                // Calculate the area using Heron's formula
                area = sqrt(s * (s - d1) * (s - d2) * (s - d3));

                // Display the area with 3 decimal places
                printf("area %.3f\n", area);
            }
        }
    }

    return 0;
}

